import type { AccuracyLevel, QuotaStatus, RateLimitStatus, ResetPrediction, ResetRule, UsageEvent } from '../types';
import { formatDateTime } from './format';
import { clamp, sum } from './utils';

function parseAnchor(anchor = '00:00'): { hours: number; minutes: number } {
  const [hours, minutes] = anchor.split(':').map((value) => Number.parseInt(value, 10));
  return {
    hours: Number.isFinite(hours) ? hours : 0,
    minutes: Number.isFinite(minutes) ? minutes : 0
  };
}

export function getCurrentWindowBounds(rule: ResetRule, now = Date.now()): { start?: number; end?: number } {
  const date = new Date(now);
  switch (rule.kind) {
    case 'rolling': {
      const intervalMs = (rule.intervalMinutes ?? 180) * 60_000;
      return { start: now - intervalMs, end: now + intervalMs };
    }
    case 'hourly': {
      const intervalMinutes = rule.intervalMinutes ?? 60;
      const current = new Date(now);
      const minutes = current.getMinutes();
      const snappedMinutes = Math.floor(minutes / intervalMinutes) * intervalMinutes;
      current.setMinutes(snappedMinutes, 0, 0);
      const start = current.getTime();
      return { start, end: start + intervalMinutes * 60_000 };
    }
    case 'daily': {
      const { hours, minutes } = parseAnchor(rule.anchorLocalTime);
      const start = new Date(now);
      start.setHours(hours, minutes, 0, 0);
      if (start.getTime() > now) {
        start.setDate(start.getDate() - 1);
      }
      const end = new Date(start);
      end.setDate(end.getDate() + 1);
      return { start: start.getTime(), end: end.getTime() };
    }
    case 'weekly': {
      const targetDay = rule.dayOfWeek ?? 1;
      const start = new Date(now);
      const { hours, minutes } = parseAnchor(rule.anchorLocalTime);
      start.setHours(hours, minutes, 0, 0);
      const currentDay = start.getDay();
      const delta = (currentDay - targetDay + 7) % 7;
      start.setDate(start.getDate() - delta);
      if (start.getTime() > now) {
        start.setDate(start.getDate() - 7);
      }
      const end = new Date(start);
      end.setDate(end.getDate() + 7);
      return { start: start.getTime(), end: end.getTime() };
    }
    case 'custom': {
      const intervalMs = (rule.intervalMinutes ?? 1440) * 60_000;
      return { start: now - intervalMs, end: now + intervalMs };
    }
    case 'unknown':
    default:
      return {};
  }
}

export function predictReset(options: {
  events?: UsageEvent[];
  rule?: ResetRule;
  explicitResetAt?: number;
  now?: number;
}): ResetPrediction {
  const now = options.now ?? Date.now();
  const explicitResetAt = options.explicitResetAt;
  const rule = options.rule ?? { kind: 'unknown', inferred: true };

  if (explicitResetAt && explicitResetAt > now) {
    return {
      resetAt: explicitResetAt,
      remainingMs: explicitResetAt - now,
      windowEnd: explicitResetAt,
      localLabel: formatDateTime(explicitResetAt),
      kind: rule.kind,
      confidence: 'exact',
      explanation: 'Detected from the site UI or a rate-limit message.'
    };
  }

  switch (rule.kind) {
    case 'rolling': {
      const intervalMs = (rule.intervalMinutes ?? 180) * 60_000;
      const recentEvents = [...(options.events ?? [])].filter((event) => event.timestamp >= now - intervalMs).sort((a, b) => a.timestamp - b.timestamp);
      const oldest = recentEvents[0]?.timestamp ?? now;
      const resetAt = oldest + intervalMs;
      return {
        resetAt,
        remainingMs: Math.max(0, resetAt - now),
        windowStart: oldest,
        windowEnd: resetAt,
        localLabel: formatDateTime(resetAt),
        kind: 'rolling',
        confidence: rule.inferred ? 'inferred' : 'estimated',
        explanation: recentEvents.length
          ? 'Estimated from the oldest observed event inside the rolling usage window.'
          : 'Estimated from the configured rolling window because no exact reset signal was available.'
      };
    }
    case 'hourly':
    case 'daily':
    case 'weekly':
    case 'custom': {
      const { start, end } = getCurrentWindowBounds(rule, now);
      return {
        resetAt: end,
        remainingMs: end ? Math.max(0, end - now) : undefined,
        windowStart: start,
        windowEnd: end,
        localLabel: end ? formatDateTime(end) : 'Unknown',
        kind: rule.kind,
        confidence: rule.inferred ? 'inferred' : 'estimated',
        explanation: 'Estimated from the configured reset schedule.'
      };
    }
    case 'unknown':
    default:
      return {
        localLabel: 'Unknown',
        kind: 'unknown',
        confidence: 'inferred',
        explanation: 'No explicit reset rule or rate-limit signal was detected yet.'
      };
  }
}

export function computeQuotaStatus(options: {
  events: UsageEvent[];
  rule?: ResetRule;
  tokenBudget?: number;
  quotaTier?: string;
  explicitResetAt?: number;
  remainingTokensHint?: number;
  percentUsedHint?: number;
  statusHint?: RateLimitStatus;
  now?: number;
}): QuotaStatus {
  const now = options.now ?? Date.now();
  const rule = options.rule ?? { kind: 'unknown', inferred: true };
  const prediction = predictReset({
    events: options.events,
    rule,
    explicitResetAt: options.explicitResetAt,
    now
  });

  const currentWindowEvents = (() => {
    if (rule.kind === 'rolling') {
      const intervalMs = (rule.intervalMinutes ?? 180) * 60_000;
      return options.events.filter((event) => event.timestamp >= now - intervalMs);
    }
    if (prediction.windowStart !== undefined) {
      return options.events.filter((event) => event.timestamp >= prediction.windowStart!);
    }
    return options.events;
  })();

  const usedTokens = sum(currentWindowEvents.map((event) => event.totalTokens));
  const remainingTokens = options.tokenBudget !== undefined
    ? Math.max(0, options.tokenBudget - usedTokens)
    : options.remainingTokensHint;
  const percentUsed = options.tokenBudget !== undefined
    ? clamp((usedTokens / Math.max(1, options.tokenBudget)) * 100, 0, 100)
    : options.percentUsedHint;

  let status: RateLimitStatus = options.statusHint ?? 'unknown';
  if (status === 'unknown') {
    if (currentWindowEvents.some((event) => event.status === 'rate_limited')) {
      status = 'limited';
    } else if (percentUsed !== undefined && percentUsed >= 100) {
      status = 'limited';
    } else if (percentUsed !== undefined && percentUsed >= 85) {
      status = 'warning';
    } else if (currentWindowEvents.length > 0) {
      status = 'ok';
    }
  }

  const accuracy: AccuracyLevel = options.explicitResetAt
    ? 'exact'
    : prediction.confidence;

  return {
    usedTokens,
    remainingTokens,
    percentUsed,
    status,
    quotaTier: options.quotaTier,
    resetRule: rule,
    accuracy,
    explicitResetAt: options.explicitResetAt,
    nextReset: prediction
  };
}
