import type { SiteAdapter } from '../types';
import { chatgptAdapter } from './chatgpt';
import { claudeAdapter } from './claude';
import { geminiAdapter } from './gemini';
import { grokAdapter } from './grok';
import { perplexityAdapter } from './perplexity';

const adapters: SiteAdapter[] = [chatgptAdapter, claudeAdapter, geminiAdapter, perplexityAdapter, grokAdapter];

export function getAdapterForCurrentSite(): SiteAdapter | undefined {
  const url = new URL(window.location.href);
  return adapters.find((adapter) => adapter.matches(url));
}
