import type { AdapterQuotaHints, AttachmentDescriptor, NormalizedMessage, SiteAdapter, SiteId } from '../types';
import { hashString } from '../lib/utils';

interface SelectorConfig {
  site: SiteId;
  label: string;
  hostnames: string[];
  composer: string[];
  sendButton: string[];
  conversationRoot: string[];
  userMessage: string[];
  assistantMessage: string[];
  model: string[];
  attachment: string[];
  alert: string[];
}

function queryFirst(selectors: string[], root: ParentNode = document): HTMLElement | null {
  for (const selector of selectors) {
    const element = root.querySelector<HTMLElement>(selector);
    if (element) return element;
  }
  return null;
}

function queryAll(selectors: string[], root: ParentNode = document): HTMLElement[] {
  const elements: HTMLElement[] = [];
  for (const selector of selectors) {
    elements.push(...Array.from(root.querySelectorAll<HTMLElement>(selector)));
  }
  return Array.from(new Set(elements));
}

function textFromNode(node: HTMLElement): string {
  const input = node as HTMLInputElement | HTMLTextAreaElement;
  const directValue = typeof input.value === 'string' ? input.value : '';
  const content = directValue || node.innerText || node.textContent || '';
  return content.replace(/\u00a0/g, ' ').replace(/\n{3,}/g, '\n\n').trim();
}

function cleanModelName(value?: string): string | undefined {
  if (!value) return undefined;
  return value.replace(/\s+/g, ' ').replace(/\bnew\b/gi, '').trim().slice(0, 80) || undefined;
}

function parseRelativeReset(text: string): number | undefined {
  const minutesMatch = text.match(/(?:in|after)\s+(\d+)\s+minutes?/i);
  if (minutesMatch) {
    return Date.now() + Number.parseInt(minutesMatch[1], 10) * 60_000;
  }
  const hoursMatch = text.match(/(?:in|after)\s+(\d+)\s+hours?/i);
  if (hoursMatch) {
    return Date.now() + Number.parseInt(hoursMatch[1], 10) * 3_600_000;
  }
  const clockMatch = text.match(/(?:until|at|after)\s+(\d{1,2}:\d{2}\s*(?:AM|PM))/i);
  if (clockMatch) {
    const parsed = new Date(`${new Date().toDateString()} ${clockMatch[1]}`);
    if (!Number.isNaN(parsed.getTime())) {
      if (parsed.getTime() < Date.now()) parsed.setDate(parsed.getDate() + 1);
      return parsed.getTime();
    }
  }
  const absoluteMatch = text.match(/((?:Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec)[a-z]*\s+\d{1,2}(?:,\s*\d{4})?(?:\s+at)?\s+\d{1,2}:\d{2}\s*(?:AM|PM))/i);
  if (absoluteMatch) {
    const parsed = new Date(absoluteMatch[1]);
    return Number.isNaN(parsed.getTime()) ? undefined : parsed.getTime();
  }
  return undefined;
}

function parseQuotaHintsFromText(text: string): AdapterQuotaHints {
  const normalized = text.replace(/\s+/g, ' ').trim();
  if (!normalized) return {};

  const limited = /(?:usage|rate|message|token) limit|too many requests|try again later|quota/i.test(normalized);
  const remainingMatch = normalized.match(/(\d[\d,]*)\s+(?:tokens|messages)\s+remaining/i);
  const percentMatch = normalized.match(/(\d{1,3})\s*%\s*(?:used|remaining)/i);
  const tierMatch = normalized.match(/\b(plus|pro|advanced|premium|free)\b/i);

  return {
    resetAt: parseRelativeReset(normalized),
    rateLimitMessage: limited ? normalized.slice(0, 220) : undefined,
    remainingTokens: remainingMatch ? Number.parseInt(remainingMatch[1].replace(/,/g, ''), 10) : undefined,
    percentUsed: percentMatch ? Number.parseInt(percentMatch[1], 10) : undefined,
    quotaTier: tierMatch?.[1] ? tierMatch[1][0].toUpperCase() + tierMatch[1].slice(1).toLowerCase() : undefined,
    status: limited ? 'limited' : undefined,
    confidence: limited || remainingMatch || percentMatch ? 0.72 : 0.2
  };
}

function inferThreadIdFromLocation(site: SiteId): string {
  const url = new URL(window.location.href);
  const pathParts = url.pathname.split('/').filter(Boolean);
  const queryThread = url.searchParams.get('conversation') || url.searchParams.get('thread');
  if (queryThread) return queryThread;
  if (pathParts.length) return `${site}:${pathParts[pathParts.length - 1]}`;
  return `${site}:root`;
}

export class SelectorSiteAdapter implements SiteAdapter {
  site: SiteId;
  label: string;
  private config: SelectorConfig;

  constructor(config: SelectorConfig) {
    this.config = config;
    this.site = config.site;
    this.label = config.label;
  }

  matches(url: URL): boolean {
    return this.config.hostnames.some((hostname) => url.hostname === hostname || url.hostname.endsWith(`.${hostname}`));
  }

  getComposer(): HTMLElement | null {
    return queryFirst(this.config.composer);
  }

  readComposerText(): string {
    const composer = this.getComposer();
    return composer ? textFromNode(composer) : '';
  }

  getSendButton(): HTMLElement | null {
    return queryFirst(this.config.sendButton);
  }

  getConversationRoot(): HTMLElement | null {
    return queryFirst(this.config.conversationRoot) ?? document.body;
  }

  collectMessages(): NormalizedMessage[] {
    const messages = queryAll([...this.config.userMessage, ...this.config.assistantMessage]);
    const normalized = messages
      .map((node, index) => {
        const role = node.matches(this.config.userMessage.join(',')) ? 'user' : 'assistant';
        const text = textFromNode(node);
        return {
          id: `${role}_${hashString(`${text}:${index}`)}`,
          role,
          text,
          timestamp: Date.now()
        } as NormalizedMessage;
      })
      .filter((message) => message.text.length > 1);

    if (normalized.length) return normalized;

    const genericNodes = Array.from(document.querySelectorAll<HTMLElement>('[data-message-author-role], article, .message, .prose'))
      .map((node, index) => {
        const authorRole = node.getAttribute('data-message-author-role');
        const role = authorRole === 'user' ? 'user' : authorRole === 'assistant' ? 'assistant' : index % 2 === 0 ? 'assistant' : 'user';
        return {
          id: `${role}_${hashString(`${textFromNode(node)}:${index}`)}`,
          role,
          text: textFromNode(node),
          timestamp: Date.now()
        } as NormalizedMessage;
      })
      .filter((message) => message.text.length > 12)
      .slice(-30);

    return genericNodes;
  }

  getModelName(): string | undefined {
    const modelElement = queryFirst(this.config.model);
    return cleanModelName(modelElement?.innerText || modelElement?.textContent || undefined);
  }

  getThreadId(): string {
    return inferThreadIdFromLocation(this.site);
  }

  getAttachmentDescriptors(): AttachmentDescriptor[] {
    return queryAll(this.config.attachment).map((node) => {
      const name = textFromNode(node).slice(0, 120) || node.getAttribute('aria-label') || 'Attachment';
      const sizeHint = node.getAttribute('data-size') || node.getAttribute('aria-description') || '';
      const sizeMatch = sizeHint.match(/(\d+(?:\.\d+)?)\s*(KB|MB|GB)/i);
      let sizeBytes: number | undefined;
      if (sizeMatch) {
        const value = Number.parseFloat(sizeMatch[1]);
        const unit = sizeMatch[2].toUpperCase();
        sizeBytes = unit === 'GB' ? value * 1024 ** 3 : unit === 'MB' ? value * 1024 ** 2 : value * 1024;
      }
      return {
        name,
        sizeBytes
      } satisfies AttachmentDescriptor;
    });
  }

  getQuotaHints(): AdapterQuotaHints {
    const alertNodes = queryAll(this.config.alert);
    const text = alertNodes.map((node) => textFromNode(node)).join(' • ');
    return parseQuotaHintsFromText(text || document.body.innerText.slice(0, 2000));
  }
}
