function makeResetRule(kind: ResetRule['kind'], description: string, intervalMinutes?: number): ResetRule {
  return {
    kind,
    intervalMinutes,
    inferred: true,
    description
  };
}

function makeSiteSettings(site: SiteId): SiteSettings {
  const defaults: Record<SiteId, SiteSettings> = {
    chatgpt: {
      enabled: true,
      resetRule: makeResetRule('rolling', 'Inferred rolling window. Adjust in settings if your plan differs.', 180),
      quotaTierLabel: 'Auto-detect'
    },
    claude: {
      enabled: true,
      resetRule: {
        kind: 'daily',
        anchorLocalTime: '00:00',
        inferred: true,
        description: 'Inferred daily reset. Adjust if needed.'
      },
      quotaTierLabel: 'Auto-detect'
    },
    gemini: {
      enabled: true,
      resetRule: {
        kind: 'daily',
        anchorLocalTime: '00:00',
        inferred: true,
        description: 'Inferred daily reset. Adjust if needed.'
      },
      quotaTierLabel: 'Auto-detect'
    },
    perplexity: {
      enabled: true,
      resetRule: {
        kind: 'daily',
        anchorLocalTime: '00:00',
        inferred: true,
        description: 'Inferred daily reset. Adjust if needed.'
      },
      quotaTierLabel: 'Auto-detect'
    },
    grok: {
      enabled: true,
      resetRule: {
        kind: 'daily',
        anchorLocalTime: '00:00',
        inferred: true,
        description: 'Inferred daily reset. Adjust if needed.'
      },
      quotaTierLabel: 'Auto-detect'
    },
    generic: {
      enabled: false,
      resetRule: {
        kind: 'unknown',
        inferred: true,
        description: 'Set a custom reset rule once you know the platform limits.'
      },
      quotaTierLabel: 'Custom'
    }
  };

  return structuredClone(defaults[site]);
}

