import type { PromptAnalysis, QuotaStatus } from '../types';
import { SITE_LABELS } from '../lib/constants';
import { formatDuration, formatPercent, formatTokens } from '../lib/format';

const styles = `
:host { all: initial; }
.yor-root {
  position: fixed;
  right: 20px;
  bottom: 20px;
  z-index: 2147483647;
  width: 340px;
  max-width: calc(100vw - 32px);
  color: #f5f7fb;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}
.yor-card {
  border-radius: 22px;
  overflow: hidden;
  background: linear-gradient(180deg, rgba(12,16,27,0.94), rgba(16,22,34,0.88));
  backdrop-filter: blur(20px);
  border: 1px solid rgba(255,255,255,0.1);
  box-shadow: 0 24px 60px rgba(0,0,0,0.36);
}
.yor-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 14px 16px 12px;
  background: linear-gradient(135deg, rgba(92,123,255,0.18), rgba(70,232,195,0.08));
}
.yor-title { display:flex; flex-direction:column; gap:4px; }
.yor-title strong { font-size: 14px; letter-spacing: 0.01em; }
.yor-title span { font-size: 11px; opacity: 0.78; }
.yor-chip { font-size: 11px; padding: 6px 10px; border-radius: 999px; background: rgba(255,255,255,0.08); }
.yor-body { padding: 14px 16px 16px; display: grid; gap: 14px; }
.yor-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; }
.yor-stat { padding: 10px; border-radius: 14px; background: rgba(255,255,255,0.045); display:grid; gap:4px; }
.yor-stat-label { font-size: 10px; text-transform: uppercase; letter-spacing: 0.08em; opacity: 0.65; }
.yor-stat-value { font-size: 15px; font-weight: 700; }
.yor-meter { height: 10px; border-radius: 999px; background: rgba(255,255,255,0.08); overflow: hidden; }
.yor-meter > span { display:block; height:100%; border-radius:inherit; background: linear-gradient(90deg, #70f0cb, #74a7ff 56%, #ff5f6d); }
.yor-list { margin:0; padding-left: 18px; display:grid; gap: 6px; font-size:12px; color: rgba(245,247,251,0.88); }
.yor-actions { display:flex; gap:8px; flex-wrap:wrap; }
.yor-button {
  border:0; border-radius:12px; padding:10px 12px; cursor:pointer; color:#f8fbff;
  background: rgba(255,255,255,0.08); font: inherit; font-size:12px; font-weight:600;
}
.yor-button.primary { background: linear-gradient(135deg, #6d8dff, #57d9b4); color: #0b1220; }
.yor-foot { display:flex; justify-content:space-between; align-items:center; font-size:11px; opacity:0.75; }
.yor-hidden { display:none; }
@media (max-width: 768px) {
  .yor-root { right: 12px; left: 12px; width: auto; bottom: 12px; }
}
`;

export interface OverlayRenderState {
  site: string;
  model: string;
  analysis: PromptAnalysis;
  quota: QuotaStatus;
  threadTokens: number;
  privacyLabel: string;
}

export interface OverlayCallbacks {
  onCopyShorter: () => void;
  onReplacePrompt: () => void;
  onToggle: () => void;
}

export class OverlayWidget {
  private container: HTMLDivElement;
  private shadow: ShadowRoot;
  private visible = true;
  private collapsed = false;
  private state?: OverlayRenderState;
  private callbacks: OverlayCallbacks;

  constructor(callbacks: OverlayCallbacks) {
    this.callbacks = callbacks;
    this.container = document.createElement('div');
    this.container.className = 'yor-token-usage-root';
    this.shadow = this.container.attachShadow({ mode: 'open' });
    this.shadow.innerHTML = `<style>${styles}</style>`;
    document.documentElement.appendChild(this.container);
  }

  setVisible(value: boolean): void {
    this.visible = value;
    this.container.style.display = value ? '' : 'none';
  }

  toggleCollapsed(): void {
    this.collapsed = !this.collapsed;
    this.render(this.state);
  }

  render(state?: OverlayRenderState): void {
    if (!state) return;
    this.state = state;
    const percent = state.quota.percentUsed ?? 0;
    const resetMs = state.quota.nextReset?.remainingMs;
    const suggestions = state.analysis.suggestions.slice(0, 3);
    const statusText = state.quota.status === 'limited'
      ? 'Limited'
      : state.quota.status === 'warning'
        ? 'Near limit'
        : state.quota.accuracy === 'exact'
          ? 'Live'
          : 'Estimated';

    this.shadow.innerHTML = `
      <style>${styles}</style>
      <div class="yor-root ${this.visible ? '' : 'yor-hidden'}">
        <div class="yor-card">
          <div class="yor-head">
            <div class="yor-title">
              <strong>Yor Token Usage</strong>
              <span>${SITE_LABELS[state.site as keyof typeof SITE_LABELS] ?? state.site} • ${state.model || 'Unknown model'}</span>
            </div>
            <button class="yor-button" data-action="toggle">${this.collapsed ? 'Expand' : 'Minimize'}</button>
          </div>
          <div class="yor-body ${this.collapsed ? 'yor-hidden' : ''}">
            <div class="yor-grid">
              <div class="yor-stat">
                <span class="yor-stat-label">Input</span>
                <span class="yor-stat-value">${formatTokens(state.analysis.inputTokens)}</span>
              </div>
              <div class="yor-stat">
                <span class="yor-stat-label">Quota</span>
                <span class="yor-stat-value">${state.quota.remainingTokens !== undefined ? formatTokens(state.quota.remainingTokens) : formatPercent(percent)}</span>
              </div>
              <div class="yor-stat">
                <span class="yor-stat-label">Reset</span>
                <span class="yor-stat-value">${resetMs !== undefined ? formatDuration(resetMs) : 'Unknown'}</span>
              </div>
            </div>
            <div>
              <div class="yor-foot"><span>${statusText}</span><span>${formatPercent(percent)}</span></div>
              <div class="yor-meter"><span style="width: ${Math.min(100, Math.max(percent, 4))}%"></span></div>
            </div>
            <div class="yor-grid">
              <div class="yor-stat">
                <span class="yor-stat-label">Thread</span>
                <span class="yor-stat-value">${formatTokens(state.threadTokens)}</span>
              </div>
              <div class="yor-stat">
                <span class="yor-stat-label">Savings</span>
                <span class="yor-stat-value">${state.analysis.compressionScore}%</span>
              </div>
              <div class="yor-stat">
                <span class="yor-stat-label">Privacy</span>
                <span class="yor-stat-value">${state.privacyLabel}</span>
              </div>
            </div>
            <div>
              <div class="yor-foot"><span>Top suggestions</span><span>${suggestions.length}</span></div>
              <ul class="yor-list">
                ${suggestions.length ? suggestions.map((item) => `<li>${item.title} • save ~${formatTokens(item.estimatedSavings)}</li>`).join('') : '<li>No urgent optimizations right now.</li>'}
              </ul>
            </div>
            <div class="yor-actions">
              <button class="yor-button primary" data-action="copy-shorter">Copy shorter</button>
              <button class="yor-button" data-action="replace-prompt">Replace prompt</button>
            </div>
          </div>
        </div>
      </div>
    `;

    this.shadow.querySelector('[data-action="copy-shorter"]')?.addEventListener('click', () => this.callbacks.onCopyShorter());
    this.shadow.querySelector('[data-action="replace-prompt"]')?.addEventListener('click', () => this.callbacks.onReplacePrompt());
    this.shadow.querySelector('[data-action="toggle"]')?.addEventListener('click', () => this.toggleCollapsed());
  }
}
